	private List<String> assertRowsMatch(java.nio.file.Path tempDir, String query, Map<String, Value> bindings) {
		Repository fallbackRepository = createRepository(tempDir.resolve("fallback").toFile(), false, false);
		Repository interpretedRepository = createRepository(tempDir.resolve("interpreted").toFile(), true, false);
		Repository compiledRepository = createRepository(tempDir.resolve("compiled").toFile(), true, true);

		try {
			populate(fallbackRepository);
			populate(interpretedRepository);
			populate(compiledRepository);

			List<String> expected = executeRows(fallbackRepository, query, bindings);
			List<String> interpreted = executeRows(interpretedRepository, query, bindings);
			List<String> compiled = executeRows(compiledRepository, query, bindings);

			assertEquals(expected, interpreted, "Interpreted LFTJ must preserve query rows");
			assertEquals(expected, compiled, "Compiled LFTJ must preserve query rows");
			return expected;
		} finally {
			fallbackRepository.shutDown();
			interpretedRepository.shutDown();
			compiledRepository.shutDown();
		}
	}

	private Repository createRepository(File dataDir, boolean lftjEnabled, boolean lftjCodegenEnabled) {
		LmdbStoreConfig config = new LmdbStoreConfig("spoc,sopc,psoc,posc,ospc,opsc");
		config.setLftjEnabled(lftjEnabled);
		config.setLftjCodegenEnabled(lftjCodegenEnabled);
		config.setForceSync(false);
		config.setValueDBSize(1_073_741_824L);
		config.setTripleDBSize(config.getValueDBSize());

		Repository repository = new SailRepository(new LmdbStore(dataDir, config));
		repository.init();
		return repository;
	}

	private void populate(Repository repository) {
		try (SailRepositoryConnection connection = (SailRepositoryConnection) repository.getConnection()) {
			for (long subject = 1; subject <= 4; subject++) {
				for (long object = 1; object <= 4; object++) {
					if (subject != object) {
						connection.add(person(subject), org.eclipse.rdf4j.model.vocabulary.FOAF.KNOWS, person(object));
					}
				}
			}
		}
	}

	private List<String> executeRows(Repository repository, String query, Map<String, Value> bindings) {
		List<String> rows = new ArrayList<>();
		try (RepositoryConnection connection = repository.getConnection()) {
			TupleQuery tupleQuery = connection.prepareTupleQuery(query);
			for (Map.Entry<String, Value> binding : bindings.entrySet()) {
				tupleQuery.setBinding(binding.getKey(), binding.getValue());
			}
			try (TupleQueryResult result = tupleQuery.evaluate()) {
				while (result.hasNext()) {
					rows.add(render(result.next()));
				}
			}
		}
		Collections.sort(rows);
		return rows;
	}

	private String render(BindingSet row) {
		List<String> names = new ArrayList<>(row.getBindingNames());
		Collections.sort(names);
		StringBuilder builder = new StringBuilder();
		for (int i = 0; i < names.size(); i++) {
			if (i > 0) {
				builder.append('|');
			}
			String name = names.get(i);
			builder.append(name).append('=').append(row.getValue(name).stringValue());
		}
		return builder.toString();
	}

